  const totalRating = reviews.reduce((sum, r) => sum + r.rating, 0);
  const overallRating = reviews.length > 0 ? Math.round((totalRating / reviews.length) * 10) / 10 : undefined;

  return {
    reviews,
    productName,
    overallRating,
    totalGlobalRatings: reviews.length,
  };
}

