  Amazon: {
    urlSupported: true,
    placeholder: "https://www.amazon.com/dp/B0...",
    helpText: "Enter the Amazon product page URL. Reviews will be extracted automatically.",
  },
  "Google Maps": {
    urlSupported: true,
    placeholder: "https://www.google.com/maps/place/...",
    helpText: "Enter a Google Maps place URL. Reviews will be extracted automatically.",
  },
