        </TabsContent>

        <TabsContent value="csv" className="space-y-4 mt-5">
          <div>
            <label className="text-xs font-medium text-white/50 mb-1.5 block uppercase tracking-wider">
              Product Name
            </label>
            <Input
              placeholder="e.g., Apple AirPods Pro (2nd Gen)"
